// Extract lead data from incoming payload or fetch from Supabase
const input = $input.first().json.body;
let lead;

if (input.lead_id) {
  // Lead ID provided - trigger expects fetch from DB
  lead = { lead_id: input.lead_id };
} else if (input.customer_name) {
  // Full lead data provided - use directly
  lead = input;
} else {
  throw new Error('No lead_id or customer_name provided in payload');
}

return lead;

// Parse AI response and merge with lead data
const aiResponse = $input.first().json;

let analysis;
try {
  // Try to parse JSON from AI response
  const text = aiResponse.output || aiResponse.text || aiResponse.message || '{}';
  analysis = typeof text === 'string' ? JSON.parse(text) : text;
} catch (e) {
  console.error('[AI ANALYSIS] Failed to parse AI response as JSON:', e.message);
  // Fallback defaults
  analysis = {
    summary: $json.issue_description || 'No summary available',
    recommended_action: 'Review lead manually',
    lead_quality: 'MEDIUM',
    urgency: 'NORMAL',
    estimated_job_value: 'MEDIUM',
    customer_intent: 'UNKNOWN',
    service_category: 'General',
    recommended_response_time: 'Within 24 Hours',
    lead_score: 50,
    priority: 'MEDIUM'
  };
}

return {
  lead_id: $json.id,
  summary: analysis.summary || analysis.Summary,
  recommended_action: analysis.recommended_action || analysis.RecommendedAction,
  lead_quality: (analysis.lead_quality || analysis.Quality || 'MEDIUM').toUpperCase(),
  urgency: (analysis.urgency || analysis.Urgency || 'NORMAL').toUpperCase(),
  estimated_job_value: (analysis.estimated_job_value || analysis.EstimatedJobValue || 'MEDIUM').toUpperCase(),
  customer_intent: (analysis.customer_intent || analysis.CustomerIntent || 'UNKNOWN').toUpperCase(),
  service_category: analysis.service_category || analysis.ServiceCategory || 'General',
  recommended_response_time: analysis.recommended_response_time || analysis.RecommendedResponseTime || 'Within 24 Hours',
  lead_score: parseInt(analysis.lead_score || analysis.Score || 50, 10),
  priority: (analysis.priority || analysis.Priority || 'MEDIUM').toUpperCase()
};

const error = $input.first().json.error || 'AI Analysis failed';
console.error('[AI ANALYSIS ERROR]', error);
return { success: false, error: error.message || error };
